public class LoggingService : ILoggingService
{
    public void Configure()
    {
        var logFolder = Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
            "GoogleCalendarManagement", "logs");
        Directory.CreateDirectory(logFolder);

        Log.Logger = new LoggerConfiguration()
#if DEBUG
            .MinimumLevel.Debug()
#else
            .MinimumLevel.Information()
#endif
            .MinimumLevel.Override("Microsoft", LogEventLevel.Warning)
            .MinimumLevel.Override("Microsoft.EntityFrameworkCore", LogEventLevel.Warning)
            .Enrich.FromLogContext()
            .Enrich.WithProperty("Application", "GoogleCalendarManagement")
            .Enrich.WithProperty("Version",
                Assembly.GetExecutingAssembly().GetName().Version?.ToString() ?? "unknown")
            .WriteTo.Console()
            .WriteTo.File(
                path: Path.Combine(logFolder, "app-.txt"),
                rollingInterval: RollingInterval.Day,
                retainedFileCountLimit: 30,
                outputTemplate: "{Timestamp:yyyy-MM-dd HH:mm:ss} [{Level:u3}] {Message:lj}{NewLine}{Exception}")
            .CreateLogger();
    }
}

private static void ConfigureServices(ServiceCollection services)
{
    // Serilog bridges to Microsoft.Extensions.Logging ILogger<T>
    services.AddSerilog();

    // Remove: services.AddLogging(builder => { builder.AddDebug(); ... })

    services.AddSingleton<ILoggingService, LoggingService>();
    services.AddSingleton<IErrorHandlingService, ErrorHandlingService>();

    var localAppData = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
    var dbFolder = Path.Combine(localAppData, "GoogleCalendarManagement");
    Directory.CreateDirectory(dbFolder);
    var dbPath = Path.Combine(dbFolder, "calendar.db");

    var dbOptions = new DatabaseOptions { ConnectionString = $"Data Source={dbPath}" };
    services.AddSingleton(dbOptions);
    services.AddDbContext<CalendarDbContext>(options =>
        options.UseSqlite(dbOptions.ConnectionString)
               .AddInterceptors(new SqliteConnectionInterceptor()));

    services.AddScoped<IMigrationService, MigrationService>();
}

// In MigrationService.RunStartupAsync():
using (Operation.Time("Database migration"))
{
    await _context.Database.MigrateAsync();
}
// Logs at Information if <1s: "Database migration completed in 523ms"
// Logs at Warning if >1s:    "Database migration completed in 1523ms (slow)"
